// TypeScript infers types from values
let city = "New York"; // string
let population = 8336817; // number
let isCapital = false; // boolean

// Function return type is inferred
function divide(a: number, b: number) {
  return a / b; // inferred: number
}

// Contextual typing
const items = [1, 2, 3];
items.push(4); // OK, items is number[]
// items.push("5"); // Error
